import React, { useEffect, useState } from 'react';
import { useStudioStore } from '../../store/useStudioStore';
import { AgentomaticClient } from '../../api/client';
import { PipelineInfo } from '../../api/types';

export const PipelinesView: React.FC = () => {
  const { config, darkMode } = useStudioStore();
  const [pipelines, setPipelines] = useState<PipelineInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchPipelines = async () => {
      try {
        if (!config?.apiUrl) return;
        const client = new AgentomaticClient(config.apiUrl, config.apiKey || undefined);
        const data = await client.listPipelines();
        setPipelines(data);
        setError(null);
      } catch (err: any) {
        setError(err.message || 'Failed to fetch pipelines');
      } finally {
        setLoading(false);
      }
    };
    fetchPipelines();
  }, [config?.apiUrl, config?.apiKey]);

  return (
    <div className={`p-6 h-full overflow-y-auto ${darkMode ? 'text-white bg-gray-900' : 'text-gray-900 bg-gray-50'}`}>
      <h1 className="text-2xl font-bold mb-6">Pipelines</h1>
      
      {loading && <div className="text-gray-500">Loading pipelines...</div>}
      {error && <div className="text-red-500 mb-4">{error}</div>}
      
      {!loading && !error && pipelines.length === 0 && (
        <div className="text-gray-500">No pipelines found.</div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {pipelines.map(pipeline => (
          <div key={pipeline.name} className={`p-6 rounded-xl border ${darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} shadow-sm`}>
            <div className="flex justify-between items-start mb-4">
              <h2 className="text-lg font-semibold">{pipeline.name}</h2>
              <span className={`px-2 py-1 rounded text-xs ${darkMode ? 'bg-blue-900 text-blue-200' : 'bg-blue-100 text-blue-800'}`}>
                v{pipeline.version}
              </span>
            </div>
            <p className={`text-sm mb-4 ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>
              {pipeline.description || 'No description provided'}
            </p>
            <div className="mb-4">
              <h3 className="text-xs font-semibold uppercase tracking-wider text-gray-500 mb-2">Steps</h3>
              <div className="flex flex-wrap gap-2">
                {pipeline.steps.map((step, idx) => (
                  <span key={idx} className={`px-2 py-1 rounded text-xs ${darkMode ? 'bg-gray-700 text-gray-300' : 'bg-gray-100 text-gray-700'}`}>
                    {step}
                  </span>
                ))}
              </div>
            </div>
            <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700 flex justify-end">
              <button className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700">
                Run Pipeline
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
