/**
 * Default connection helpers for Agentomatic Studio.
 *
 * When the UI is served from the platform itself (`/studio/ui/...`), prefer
 * same-origin so Connect works without typing a port. Fall back to the
 * classic local Agentomatic bind address for standalone CRA/Vite dev.
 */

const LS_KEY_URL = 'agentomatic-studio:lastUrl';
const LEGACY_DEFAULT = 'http://127.0.0.1:8000';

/** True when Studio is embedded under the platform's `/studio/ui` mount. */
export function isEmbeddedStudioUi(): boolean {
  if (typeof window === 'undefined') return false;
  const path = window.location.pathname || '';
  return path.includes('/studio/ui');
}

/** Classic scaffold defaults that break when Studio is served from another port. */
function isClassicLocalDefault(url: string): boolean {
  try {
    const u = new URL(url);
    const host = u.hostname;
    const port = u.port || (u.protocol === 'https:' ? '443' : '80');
    return (
      (host === '127.0.0.1' || host === 'localhost') &&
      (port === '8000' || port === '3000')
    );
  } catch {
    return false;
  }
}

/**
 * Resolve the best default API base URL.
 *
 * Priority: persisted localStorage → same-origin (embedded) → legacy :8000.
 * When embedded under `/studio/ui`, ignore classic :8000/:3000 saves so Connect
 * targets the hosting platform (e.g. SCOOPER :18765) automatically.
 */
export function getDefaultApiUrl(): string {
  if (typeof window === 'undefined') return LEGACY_DEFAULT;
  const embedded = isEmbeddedStudioUi();
  try {
    const saved = localStorage.getItem(LS_KEY_URL);
    if (saved && /^https?:\/\//i.test(saved)) {
      const normalized = saved.replace(/\/$/, '');
      if (!(embedded && isClassicLocalDefault(normalized))) {
        return normalized;
      }
    }
  } catch {
    // ignore storage failures
  }
  if (embedded) {
    return window.location.origin;
  }
  return LEGACY_DEFAULT;
}

/** Normalize a user-entered API URL (trim, strip trailing slash). */
export function normalizeApiUrl(url: string): string {
  return (url || '').trim().replace(/\/$/, '');
}
