import type { RunEvent } from './types';

export interface SSEHandlers {
  onRunStart?: (event: RunEvent) => void;
  onNodeStart?: (event: RunEvent) => void;
  onNodeEnd?: (event: RunEvent) => void;
  onStateUpdate?: (event: RunEvent) => void;
  onMessageChunk?: (event: RunEvent) => void;
  onRunComplete?: (event: RunEvent) => void;
  onRunError?: (event: RunEvent) => void;
  onBreakpointHit?: (event: RunEvent) => void;
  onEvent?: (event: RunEvent) => void; // Catch-all
  onError?: (error: Error) => void;
  onDone?: () => void;
}

/**
 * SSE client for streaming run events.
 * Uses fetch + ReadableStream for POST-based SSE (EventSource only supports GET).
 */
export class SSEClient {
  /**
   * Connect to an SSE stream for a run execution.
   * Returns an AbortController to cancel the stream.
   */
  static connect(
    url: string,
    body: Record<string, any>,
    headers: Record<string, string>,
    handlers: SSEHandlers,
  ): AbortController {
    const controller = new AbortController();

    const run = async () => {
      try {
        const response = await fetch(url, {
          method: 'POST',
          headers: { ...headers, 'Accept': 'text/event-stream' },
          body: JSON.stringify(body),
          signal: controller.signal,
        });

        if (!response.ok) {
          throw new Error(`SSE connection failed: ${response.status} ${response.statusText}`);
        }

        const reader = response.body?.getReader();
        if (!reader) throw new Error('No response body');

        const decoder = new TextDecoder();
        let buffer = '';
        let currentEventType = ''; // Track SSE event: field

        while (true) {
          const { done, value } = await reader.read();
          if (done) {
            // Stream closed without an explicit [DONE] marker — still finish
            // so chat/debug UIs clear the "thinking…" spinner.
            handlers.onDone?.();
            break;
          }

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() || ''; // Keep incomplete line in buffer

          for (const line of lines) {
            // Track SSE event type field
            if (line.startsWith('event: ')) {
              currentEventType = line.slice(7).trim();
              continue;
            }

            if (line.startsWith('data: ')) {
              const data = line.slice(6).trim();
              if (data === '[DONE]') {
                handlers.onDone?.();
                currentEventType = '';
                return;
              }
              try {
                const event: RunEvent = JSON.parse(data);
                // If the SSE event: field was set but the JSON doesn't have it, merge it
                if (currentEventType && !event.event) {
                  (event as any).event = currentEventType;
                }
                currentEventType = ''; // Reset after consuming

                // Dispatch to specific handler
                handlers.onEvent?.(event);
                switch (event.event) {
                  case 'run_start': handlers.onRunStart?.(event); break;
                  case 'node_start': handlers.onNodeStart?.(event); break;
                  case 'node_end': handlers.onNodeEnd?.(event); break;
                  case 'state_update': handlers.onStateUpdate?.(event); break;
                  case 'message_chunk': handlers.onMessageChunk?.(event); break;
                  case 'run_complete': handlers.onRunComplete?.(event); break;
                  case 'run_error': handlers.onRunError?.(event); break;
                  case 'breakpoint_hit': handlers.onBreakpointHit?.(event); break;
                }
              } catch (parseErr) {
                console.warn('Failed to parse SSE event:', data, parseErr);
              }
            }

            // Empty line resets event type (SSE spec)
            if (line.trim() === '') {
              currentEventType = '';
            }
          }
        }
      } catch (err) {
        if ((err as Error).name !== 'AbortError') {
          handlers.onError?.(err as Error);
        }
      }
    };

    run();
    return controller;
  }
}

