import React, { useEffect, useState } from 'react';
import { useStudioStore } from '../../store/useStudioStore';
import { AgentomaticClient } from '../../api/client';
import { PluginInfo } from '../../api/types';

export const PluginsView: React.FC = () => {
  const { config, darkMode } = useStudioStore();
  const [plugins, setPlugins] = useState<PluginInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchPlugins = async () => {
      try {
        if (!config?.apiUrl) return;
        const client = new AgentomaticClient(config.apiUrl, config.apiKey || undefined);
        const data = await client.listPlugins();
        setPlugins(data);
        setError(null);
      } catch (err: any) {
        setError(err.message || 'Failed to fetch plugins');
      } finally {
        setLoading(false);
      }
    };
    fetchPlugins();
  }, [config?.apiUrl, config?.apiKey]);

  return (
    <div className={`p-6 h-full overflow-y-auto ${darkMode ? 'text-white bg-gray-900' : 'text-gray-900 bg-gray-50'}`}>
      <h1 className="text-2xl font-bold mb-6">ML Plugins</h1>
      
      {loading && <div className="text-gray-500">Loading plugins...</div>}
      {error && <div className="text-red-500 mb-4">{error}</div>}
      
      {!loading && !error && plugins.length === 0 && (
        <div className="text-gray-500">No ML plugins found.</div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {plugins.map(plugin => (
          <div key={plugin.name} className={`p-6 rounded-xl border ${darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} shadow-sm flex flex-col justify-between`}>
            <div>
              <div className="flex justify-between items-start mb-4">
                <h2 className="text-lg font-semibold">{plugin.name}</h2>
                <span className={`px-2 py-1 rounded text-xs ${darkMode ? 'bg-purple-900 text-purple-200' : 'bg-purple-100 text-purple-800'}`}>
                  v{plugin.version}
                </span>
              </div>
              <p className={`text-sm mb-4 ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>
                {plugin.description || 'No description provided'}
              </p>
              <div className="mb-4 flex items-center">
                <span className={`w-2 h-2 rounded-full mr-2 ${plugin.is_loaded ? 'bg-green-500' : 'bg-red-500'}`}></span>
                <span className="text-sm">{plugin.is_loaded ? 'Loaded' : 'Unloaded'}</span>
              </div>
            </div>
            <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700 flex justify-end gap-2">
              <button className={`px-4 py-2 rounded-lg text-sm font-medium ${darkMode ? 'bg-gray-700 hover:bg-gray-600' : 'bg-gray-200 hover:bg-gray-300'}`}>
                Model Card
              </button>
              <button className="px-4 py-2 bg-purple-600 text-white rounded-lg text-sm font-medium hover:bg-purple-700">
                Predict
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
